mapper.select:
SELECT  FROM sys_notice_read a

	${dataScope}
	 AND a.user_id = #{u.id} 
	 AND a.notice_id = #{noticeId} 

ORDER BY a.create_time DESC

mapper.insert:
INSERT INTO sys_notice_read (
	id, user_id, notice_id, notice_type, read_time, event_id, create_time, update_time
) VALUES (
	#{id}, #{u.id}, #{noticeId}, #{noticeType}, #{readTime}, #{eventId}, #{createDate}, #{updateDate}
)

mapper.update:
UPDATE sys_notice_read SET
	user_id=#{u.id}, notice_id=#{noticeId}, notice_type=#{noticeType}, read_time=#{readTime}, event_id=#{eventId}, update_time=#{updateDate}
WHERE id=#{id}
